def test_send_message_with_phi_attachment_is_blocked(auth_patient_session, provider_fixture, api_client, phi_attachment_fixture):
    payload = {
        "recipient_id": provider_fixture["id"],
        "subject": "Test",
        "body": "See attached."
    }
    files = {"attachment": phi_attachment_fixture}
    resp = api_client.post("/messages", data=payload, files=files, headers=auth_patient_session)
    assert resp.status_code == 422
    err = resp.json()
    assert err.get("error_code") == "PHI_ATTACHMENT_BLOCKED"
    exists = <message_exists_in_store>(err.get("message_id"))
    assert not exists

def test_send_message_body_at_max_character_boundary(auth_patient_session, provider_fixture, api_client):
    MAX_BODY_LEN = <get_config>("MESSAGE_MAX_BODY_LEN")
    base = {"recipient_id": provider_fixture["id"], "subject": "BVA"}

    at_limit = {**base, "body": "x" * MAX_BODY_LEN}
    resp_ok = api_client.post("/messages", json=at_limit, headers=auth_patient_session)
    assert resp_ok.status_code == 201

    over_limit = {**base, "body": "x" * (MAX_BODY_LEN + 1)}
    resp_err = api_client.post("/messages", json=over_limit, headers=auth_patient_session)
    assert resp_err.status_code in (400, 413)
    assert resp_err.json().get("error_code") == "BODY_TOO_LONG"

def test_send_message_from_unauthenticated_state_is_rejected(provider_fixture, api_client):
    payload = {
        "recipient_id": provider_fixture["id"],
        "subject": "Unauthorized attempt",
        "body": "This should be blocked."
    }
    resp = api_client.post("/messages", json=payload)
    assert resp.status_code == 401
    err = resp.json()
    assert err.get("error_code") == "UNAUTHENTICATED"
    msg_id = err.get("message_id")
    if msg_id:
        assert not <message_exists_in_store>(msg_id)

import pytest

@pytest.mark.parametrize("omit_fields", [
    ["recipient_id"],
    ["subject"],
    ["body"],
    ["subject", "body"]
])
def test_send_message_with_missing_mandatory_fields_combinations(
    auth_patient_session, provider_fixture, api_client, omit_fields
):
    full = {
        "recipient_id": provider_fixture["id"],
        "subject": "Check-in",
        "body": "How are things?"
    }
    payload = {k: v for k, v in full.items() if k not in omit_fields}
    resp = api_client.post("/messages", json=payload, headers=auth_patient_session)
    assert resp.status_code == 400
    assert resp.json().get("error_code") == "MISSING_REQUIRED_FIELD"
